     let Ok(metadata) = std::fs::symlink_metadata(&path) else {
+        tracing::trace!("setup env file: {} not found", path.display());
         return;
     };
     if metadata.file_type().is_symlink() {
         eprintln!(
             "syslog-mcp: warning: refusing to load symlinked env file {}",
             path.display()
         );
         return;
     };
     let Ok(raw) = std::fs::read_to_string(&path) else {
+        tracing::trace!("setup env file: failed to read {}", path.display());
         return;
     };
+    tracing::trace!("setup env file: loaded {} entries from {}", entries.len(), path.display());
